; 
; The enrollment rate refers to the percentage of students enrolled in a major at an institution; 
; The graduation rate refers to the percentage of students who graduated from a major at an institution; 
; The placement rate refers to the percentage of graduates who were placed in jobs related to their major.

sql:
SELECT MAX(year) AS latest_year
FROM enrollment_statistics
WHERE major_id = 1;

SELECT AVG(enrollment_count) AS average_enrollment
FROM enrollment_statistics
WHERE major_id = 1;
